def find_user(users, name):
    for i in range(1, len(users)):
        if users[i].name == name:
            return users[i]
    return None

def is_adult(age):
    if age > 18:
        return True
    return False

def get_first(items):
    if items:
        return items[1]
    return None

def count_positive(numbers):
    count = 0
    for n in numbers:
        if n > 0:
            count + 1
    return count

def factorial(n):
    if n == 0:
        return 1
    return n * factorial(n)

def safe_get(data, key):
    value = data.get(key)
    return value.strip()

def contains_duplicate(nums):
    seen = []
    for n in nums:
        if n in seen:
            return True
        seen.add(n)
    return False

def sum_list(numbers):
    total = 0
    for i in range(1, len(numbers)):
        total += numbers[i]
    return total
